import{b as e,J as l,g as a,j as d}from"./chunks/framework.B_eSRemD.js";const h=JSON.parse('{"title":"계약 등록 조회","description":"","frontmatter":{},"headers":[],"relativePath":"contract/index.md","filePath":"contract/index.md","lastUpdated":1781514041000}'),r={name:"contract/index.md"};function n(i,t,s,x,y,g){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="계약-등록-조회" tabindex="-1">계약 등록 조회 <a class="header-anchor" href="#계약-등록-조회" aria-label="Permalink to &quot;계약 등록 조회&quot;">​</a></h1><p>프로젝트의 청약 및 계약 정보를 등록, 조회, 관리하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>계약 정보 관리 &gt; 계약 등록 및 조회</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>프로젝트별 청약 및 계약 현황을 한눈에 확인하고, 신규 계약을 등록하거나 기존 계약 정보를 수정 및 조회할 수 있습니다. 다양한 필터링 옵션을 통해 원하는 계약 정보를 효율적으로 검색하고, 엑셀로 출력할 수 있습니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li>프로젝트별 청약/계약 현황 요약 정보 제공</li><li>다양한 조건(차수, 타입, 동호수, 계약일 등)으로 계약 목록 필터링 및 검색</li><li>신규 청약 및 계약 등록</li><li>기존 계약 정보 수정 및 상세 조회</li><li>계약 목록 엑셀 출력 (출력 항목 선택 가능)</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-계약-현황-요약" tabindex="-1">1. 계약 현황 요약 <a class="header-anchor" href="#_1-계약-현황-요약" aria-label="Permalink to &quot;1. 계약 현황 요약&quot;">​</a></h3><p>선택된 프로젝트의 전체 청약 및 계약 현황을 타입별, 차수별로 요약하여 보여줍니다. 총 세대수, 청약 건수, 계약 건수, 잔여 세대, 계약율, 분양율 등의 주요 지표를 확인할 수 있습니다.</p><h4 id="주요-표시-항목" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><ul><li>프로젝트명</li><li>타입별 세대수, 청약건수, 계약건수 (차수별 합계 포함)</li><li>잔여세대(실), 계약율, 분양율(청약+계약)</li></ul><h3 id="_2-목록-제어-및-필터링" tabindex="-1">2. 목록 제어 및 필터링 <a class="header-anchor" href="#_2-목록-제어-및-필터링" aria-label="Permalink to &quot;2. 목록 제어 및 필터링&quot;">​</a></h3><p>계약 목록을 조회하기 위한 다양한 필터링 및 정렬 옵션을 제공합니다.</p><h4 id="주요-입력-항목" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">표시 개수</td><td style="text-align:center;"></td><td style="text-align:left;">페이지당 표시할 계약 건수 선택</td></tr><tr><td style="text-align:left;">정렬 기준</td><td style="text-align:center;"></td><td style="text-align:left;">등록일시, 계약일자, 일련번호, 계약자명 등으로 정렬</td></tr><tr><td style="text-align:left;">등록상태</td><td style="text-align:center;"></td><td style="text-align:left;">일반분양, 미인가조합원, 인가조합원, 부적격조합원 등으로 필터링</td></tr><tr><td style="text-align:left;">현황 구분</td><td style="text-align:center;"></td><td style="text-align:left;">청약 현황 또는 계약 현황 선택</td></tr><tr><td style="text-align:left;">차수 선택</td><td style="text-align:center;"></td><td style="text-align:left;">특정 차수 그룹으로 필터링</td></tr><tr><td style="text-align:left;">타입 선택</td><td style="text-align:center;"></td><td style="text-align:left;">특정 유닛 타입으로 필터링</td></tr><tr><td style="text-align:left;">공급계약</td><td style="text-align:center;"></td><td style="text-align:left;">공급계약 체결 여부로 필터링</td></tr><tr><td style="text-align:left;">동 선택</td><td style="text-align:center;"></td><td style="text-align:left;">특정 동으로 필터링</td></tr><tr><td style="text-align:left;">동호 미지정</td><td style="text-align:center;"></td><td style="text-align:left;">동호수가 미지정된 계약만 조회</td></tr><tr><td style="text-align:left;">계약일 (From/To)</td><td style="text-align:center;"></td><td style="text-align:left;">특정 기간 내 계약일로 필터링</td></tr><tr><td style="text-align:left;">검색</td><td style="text-align:center;"></td><td style="text-align:left;">계약자, 전화번호, 일련번호, 비고 등으로 검색</td></tr></tbody></table><h3 id="_3-신규-계약-등록-및-수정" tabindex="-1">3. 신규 계약 등록 및 수정 <a class="header-anchor" href="#_3-신규-계약-등록-및-수정" aria-label="Permalink to &quot;3. 신규 계약 등록 및 수정&quot;">​</a></h3><p>새로운 청약 또는 계약 정보를 등록 및 수정할 수 있는 모달 폼을 제공합니다.</p><h4 id="주요-입력-항목-contractform" tabindex="-1">주요 입력 항목 (ContractForm) <a class="header-anchor" href="#주요-입력-항목-contractform" aria-label="Permalink to &quot;주요 입력 항목 (ContractForm)&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">구분</td><td style="text-align:center;">필수</td><td style="text-align:left;">청약 또는 계약 선택</td></tr><tr><td style="text-align:left;">차수</td><td style="text-align:center;">필수</td><td style="text-align:left;">계약이 속할 차수 그룹 선택</td></tr><tr><td style="text-align:left;">타입</td><td style="text-align:center;">필수 (계약 시)</td><td style="text-align:left;">유닛 타입 선택 (공급가격 정보 미등록 시 경고 표시)</td></tr><tr><td style="text-align:left;">계약코드</td><td style="text-align:center;">필수 (유닛 설정 시)</td><td style="text-align:left;">유닛 코드 선택</td></tr><tr><td style="text-align:left;">동호수</td><td style="text-align:center;"></td><td style="text-align:left;">동호수 선택</td></tr><tr><td style="text-align:left;">공급계약</td><td style="text-align:center;"></td><td style="text-align:left;">공급계약 체결 여부 및 체결일자</td></tr><tr><td style="text-align:left;">계약일자</td><td style="text-align:center;">필수</td><td style="text-align:left;">청약일자 또는 계약일자</td></tr><tr><td style="text-align:left;">계약자명</td><td style="text-align:center;">필수</td><td style="text-align:left;">계약자 이름</td></tr><tr><td style="text-align:left;">생년월일</td><td style="text-align:center;">필수 (계약 시)</td><td style="text-align:left;">계약자 생년월일</td></tr><tr><td style="text-align:left;">성별</td><td style="text-align:center;">필수 (계약 시)</td><td style="text-align:left;">계약자 성별</td></tr><tr><td style="text-align:left;">휴대전화</td><td style="text-align:center;">필수</td><td style="text-align:left;">계약자 휴대전화 번호</td></tr><tr><td style="text-align:left;">이메일, 집전화 등</td><td style="text-align:center;"></td><td style="text-align:left;">추가 연락처 정보</td></tr><tr><td style="text-align:left;">계약금 등록/수정</td><td style="text-align:center;"></td><td style="text-align:left;">계약금 입금 정보 (입금일자, 금액, 계좌, 입금자명, 납부회차)</td></tr><tr><td style="text-align:left;">주민등록 주소</td><td style="text-align:center;">필수 (계약 시)</td><td style="text-align:left;">계약자 주민등록 주소</td></tr><tr><td style="text-align:left;">우편수령 주소</td><td style="text-align:center;">필수 (계약 시)</td><td style="text-align:left;">우편물 수령 주소 (주민등록 주소와 동일 설정 가능)</td></tr><tr><td style="text-align:left;">비고</td><td style="text-align:center;"></td><td style="text-align:left;">기타 특이사항</td></tr><tr><td style="text-align:left;">계약서 파일</td><td style="text-align:center;"></td><td style="text-align:left;">계약서 스캔본 등 첨부 파일</td></tr></tbody></table><h3 id="_4-주소-변경-등록" tabindex="-1">4. 주소 변경 등록 <a class="header-anchor" href="#_4-주소-변경-등록" aria-label="Permalink to &quot;4. 주소 변경 등록&quot;">​</a></h3><p>계약자의 주민등록 주소 및 우편물 수령 주소 이력을 관리하고, 새로운 주소로 변경 등록할 수 있는 모달 폼입니다.</p><h4 id="주요-기능-1" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능-1" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h4><ul><li>새로운 주민등록 주소 및 우편물 수령 주소 입력 (다음 우편번호 API 연동)</li><li>현재 주소와 과거 주소 이력 조회</li><li>과거 주소 이력 중 하나를 현재 주소로 다시 변경하는 기능</li></ul><h3 id="_5-계약-목록" tabindex="-1">5. 계약 목록 <a class="header-anchor" href="#_5-계약-목록" aria-label="Permalink to &quot;5. 계약 목록&quot;">​</a></h3><p>필터링 조건에 따라 조회된 계약 목록을 테이블 형태로 표시합니다. 각 계약 건에 대한 상세 정보와 수정/보기 버튼을 제공합니다.</p><h4 id="주요-표시-항목-1" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목-1" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">항목</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;">일련번호</td><td style="text-align:left;">계약의 고유 일련번호 (상세 보기 링크)</td></tr><tr><td style="text-align:left;">등록상태</td><td style="text-align:left;">계약자의 등록상태 (예: 미인가조합원, 인가조합원)</td></tr><tr><td style="text-align:left;">차수</td><td style="text-align:left;">계약이 속한 차수 그룹</td></tr><tr><td style="text-align:left;">타입</td><td style="text-align:left;">계약된 유닛의 타입</td></tr><tr><td style="text-align:left;">계약자</td><td style="text-align:left;">계약자명 (상세 보기 링크)</td></tr><tr><td style="text-align:left;">동호수</td><td style="text-align:left;">계약된 유닛의 동호수 (상세 보기 링크)</td></tr><tr><td style="text-align:left;">가입 계약일</td><td style="text-align:left;">청약 또는 가입 계약일</td></tr><tr><td style="text-align:left;">공급 계약일</td><td style="text-align:left;">공급 계약 체결일</td></tr><tr><td style="text-align:left;">공급계약가격</td><td style="text-align:left;">계약된 유닛의 공급 계약 가격</td></tr><tr><td style="text-align:left;">납입금액합계</td><td style="text-align:left;">현재까지 납입된 총 금액</td></tr><tr><td style="text-align:left;">최종납입회차</td><td style="text-align:left;">마지막으로 납입된 회차 정보</td></tr><tr><td style="text-align:left;">계약서</td><td style="text-align:left;">첨부된 계약서 파일 다운로드 링크</td></tr><tr><td style="text-align:left;">비고</td><td style="text-align:left;">계약 수정 및 상세 보기 버튼</td></tr></tbody></table><h3 id="_6-엑셀-출력-항목-선택" tabindex="-1">6. 엑셀 출력 항목 선택 <a class="header-anchor" href="#_6-엑셀-출력-항목-선택" aria-label="Permalink to &quot;6. 엑셀 출력 항목 선택&quot;">​</a></h3><p>계약 목록을 엑셀로 출력할 때 포함할 항목들을 선택할 수 있는 기능을 제공합니다.</p><h4 id="주요-선택-항목" tabindex="-1">주요 선택 항목 <a class="header-anchor" href="#주요-선택-항목" aria-label="Permalink to &quot;주요 선택 항목&quot;">​</a></h4><p>일련번호, 등록상태, 차수, 타입, 계약자, 동호수, 가입계약일, 공급계약일, 건물가, 대지가, 부가세, 공급가액, 납입금합계, 생년월일, 연락처, 이메일, 주소(등본/우편), 비고 등.</p>',32)])])}const o=e(r,[["render",n]]);export{h as __pageData,o as default};
